import { useState } from "react";
import { useAnalysisStore } from "@/store/useAnalysisStore";
import { SectionCard } from "../SectionCard";
import { Copy, Check, Download, Zap, Globe } from "lucide-react";

function CodeBlock({ content }: { content: string }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="relative rounded-xl border border-white/[0.07] bg-[#0d0d0d] overflow-hidden">
      <div className="flex items-center justify-between px-4 py-2.5 border-b border-white/[0.05]">
        <div className="flex gap-1.5">
          <div className="w-2.5 h-2.5 rounded-full bg-white/[0.07]" />
          <div className="w-2.5 h-2.5 rounded-full bg-white/[0.07]" />
          <div className="w-2.5 h-2.5 rounded-full bg-white/[0.07]" />
        </div>
        <button
          onClick={handleCopy}
          className="flex items-center gap-1.5 text-[11px] text-white/30 hover:text-white/60 transition-colors"
        >
          {copied ? <Check className="h-3 w-3" /> : <Copy className="h-3 w-3" />}
          {copied ? "Copied!" : "Copy"}
        </button>
      </div>
      <pre className="p-4 text-[12px] leading-[1.7] text-white/55 overflow-x-auto font-mono whitespace-pre-wrap">
        {content}
      </pre>
    </div>
  );
}

function PromptCard({
  tool,
  logo,
  prompt,
}: {
  tool: string;
  logo: string;
  prompt: string;
}) {
  const [expanded, setExpanded] = useState(false);
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(prompt);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="rounded-xl border border-white/[0.07] bg-white/[0.02] overflow-hidden">
      <div
        className="flex items-center justify-between px-4 py-3.5 cursor-pointer hover:bg-white/[0.03] transition-colors"
        onClick={() => setExpanded(!expanded)}
      >
        <div className="flex items-center gap-2.5">
          <span className="text-lg">{logo}</span>
          <span className="text-[13px] font-semibold text-white/75">{tool}</span>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={(e) => { e.stopPropagation(); handleCopy(); }}
            className="flex items-center gap-1 text-[11px] text-white/30 hover:text-white/60 transition-colors px-2 py-1"
          >
            {copied ? <Check className="h-3 w-3" /> : <Copy className="h-3 w-3" />}
            {copied ? "Copied" : "Copy"}
          </button>
          <span className="text-white/20 text-[12px]">{expanded ? "▲" : "▼"}</span>
        </div>
      </div>
      {expanded && (
        <div className="border-t border-white/[0.05] p-4">
          <p className="text-[12.5px] leading-[1.7] text-white/45 font-mono whitespace-pre-wrap">{prompt}</p>
        </div>
      )}
    </div>
  );
}

export function BuildModeSection() {
  const analysis = useAnalysisStore((s) => s.analysis);
  if (!analysis) return null;

  const { build_mode, product_strategy, tech_stack } = analysis;

  const idea = useAnalysisStore((s) => s.idea);
  const mvpFeatures = product_strategy.mvp_features.join("\n- ");
  const stack = `Frontend: ${tech_stack.mvp.frontend}\nBackend: ${tech_stack.mvp.backend}\nDatabase: ${tech_stack.mvp.database}`;

  const lovablePrompt = `Build a SaaS application for: ${idea}\n\nMVP Features:\n- ${mvpFeatures}\n\nTech Stack:\n${stack}\n\n${build_mode.notes_for_ai_coding_tools}`;
  const cursorPrompt = `# Project: ${idea}\n\n## Architecture\n${build_mode.project_structure}\n\n## Folder Structure\n${build_mode.suggested_folder_structure}\n\n## Modules\n${build_mode.modules.join(", ")}\n\n## Notes\n${build_mode.notes_for_ai_coding_tools}`;

  const launchOnLovable = () => {
    const prompt = `Build a SaaS app: "${analysis.branding.name_suggestions[0]}"\n\n${idea}\n\nMVP Features:\n- ${mvpFeatures}\n\nTech Stack:\n${stack}\n\n${build_mode.notes_for_ai_coding_tools}`;
    window.open(`https://lovable.dev/projects/new?prompt=${encodeURIComponent(prompt)}`, "_blank");
  };

  const copyFor10Web = () => {
    const text = `Name: ${analysis.branding.name_suggestions[0]}\nTagline: ${analysis.branding.taglines[0]}\n\n${analysis.idea_analysis.summary}\n\nFeatures:\n- ${mvpFeatures}`;
    navigator.clipboard.writeText(text);
    window.open("https://10web.io", "_blank");
  };

  return (
    <div className="space-y-4 max-w-4xl">
      <div>
        <h2 className="text-xl font-bold tracking-tight">Build Mode</h2>
        <p className="text-[13px] text-muted-foreground mt-1">
          Project structure, folder layout, and AI coding tool prompts
        </p>
      </div>

      {/* Quick Launch Actions */}
      <div className="grid sm:grid-cols-2 gap-3">
        <button
          onClick={launchOnLovable}
          className="flex items-center gap-3 p-4 rounded-xl border border-violet-500/20 bg-violet-500/5 hover:border-violet-500/40 transition-all text-left"
        >
          <Zap className="h-5 w-5 text-violet-400 shrink-0" />
          <div>
            <div className="text-[13px] font-semibold">Launch MVP on Lovable</div>
            <div className="text-[11px] text-muted-foreground mt-0.5">Generate a full-stack app from your specs</div>
          </div>
        </button>
        <button
          onClick={copyFor10Web}
          className="flex items-center gap-3 p-4 rounded-xl border border-emerald-500/20 bg-emerald-500/5 hover:border-emerald-500/40 transition-all text-left"
        >
          <Globe className="h-5 w-5 text-emerald-400 shrink-0" />
          <div>
            <div className="text-[13px] font-semibold">Launch Landing Page</div>
            <div className="text-[11px] text-muted-foreground mt-0.5">Copy branding specs &amp; open 10Web</div>
          </div>
        </button>
      </div>

      <div className="grid md:grid-cols-2 gap-4">
        <SectionCard title="Project Structure">
          <p className="text-[13px] text-muted-foreground leading-relaxed mb-3">
            {build_mode.project_structure}
          </p>
          <div className="flex flex-wrap gap-1.5">
            {build_mode.modules.map((m) => (
              <span key={m} className="text-[11px] px-2.5 py-1 rounded-lg bg-white/[0.05] border border-white/[0.07] text-white/50">
                {m}
              </span>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="Notes for AI Tools">
          <p className="text-[13px] text-muted-foreground leading-relaxed">
            {build_mode.notes_for_ai_coding_tools}
          </p>
        </SectionCard>
      </div>

      <SectionCard title="Suggested Folder Structure">
        <CodeBlock content={build_mode.suggested_folder_structure} />
      </SectionCard>

      <div>
        <h3 className="text-[14px] font-semibold mb-3">No-Code &amp; AI Builder Prompts</h3>
        <p className="text-[12px] text-muted-foreground mb-4">
          Ready-to-use prompts for popular AI coding tools. Click to expand, then copy.
        </p>
        <div className="space-y-2">
          <PromptCard tool="Lovable / Bolt.new" logo="⚡" prompt={lovablePrompt} />
          <PromptCard tool="Cursor / VS Code Copilot" logo="🖱️" prompt={cursorPrompt} />
          <PromptCard
            tool="v0 by Vercel"
            logo="▲"
            prompt={`Create a modern SaaS UI for: ${idea}\n\nKey pages: Landing, Dashboard, Settings\nDesign: Dark premium, Inter font, subtle grid background, minimal\nFeatures visible: ${product_strategy.mvp_features.slice(0, 3).join(", ")}`}
          />
        </div>
      </div>
    </div>
  );
}

import { useRef, useEffect, useState } from "react";
import { useAnalysisStore } from "@/store/useAnalysisStore";
import { SectionCard } from "../SectionCard";
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, RadarChart, Radar, PolarGrid, PolarAngleAxis,
} from "recharts";

/* ─── Gauge SVG ─────────────────────────────────────────── */
function DemandGauge({ score }: { score: number }) {
  const R = 80;
  const arc = Math.PI * R;
  const gaugeRef = useRef<SVGPathElement>(null);
  const [animated, setAnimated] = useState(false);

  useEffect(() => {
    const timer = setTimeout(() => setAnimated(true), 300);
    return () => clearTimeout(timer);
  }, []);

  const offset = arc - (score / 100) * arc;
  const color = score >= 70 ? "#6ee7b7" : score >= 45 ? "#fcd34d" : "#f87171";

  return (
    <svg viewBox="-110 -100 220 130" className="w-56 mx-auto">
      {/* Shadow glow */}
      <defs>
        <filter id="glow">
          <feGaussianBlur stdDeviation="3" result="coloredBlur" />
          <feMerge><feMergeNode in="coloredBlur" /><feMergeNode in="SourceGraphic" /></feMerge>
        </filter>
      </defs>

      {/* Track */}
      <path d={`M -${R} 0 A ${R} ${R} 0 0 1 ${R} 0`} fill="none" stroke="rgba(255,255,255,0.06)" strokeWidth="14" strokeLinecap="round" />
      {/* Fill */}
      <path
        ref={gaugeRef}
        d={`M -${R} 0 A ${R} ${R} 0 0 1 ${R} 0`}
        fill="none"
        stroke={color}
        strokeWidth="14"
        strokeLinecap="round"
        strokeDasharray={arc}
        strokeDashoffset={animated ? offset : arc}
        style={{ transition: "stroke-dashoffset 1.4s cubic-bezier(0.16,1,0.3,1)" }}
        filter="url(#glow)"
      />
      {/* Labels */}
      <text x={-R - 4} y="18" textAnchor="middle" fontSize="9" fill="rgba(255,255,255,0.3)">0</text>
      <text x={R + 4} y="18" textAnchor="middle" fontSize="9" fill="rgba(255,255,255,0.3)">100</text>
      {/* Score */}
      <text textAnchor="middle" y="-12" fontSize="38" fontWeight="900" fill="white">{score}</text>
      <text textAnchor="middle" y="10" fontSize="11" fill="rgba(255,255,255,0.4)">Demand Score</text>
    </svg>
  );
}

/* ─── Custom tooltip ────────────────────────────────────── */
function CustomTooltip({ active, payload, label }: { active?: boolean; payload?: any[]; label?: string }) {
  if (!active || !payload?.length) return null;
  return (
    <div className="bg-[#111] border border-white/[0.1] rounded-xl px-4 py-3 text-[12px] shadow-xl">
      <p className="text-white/40 mb-1">{label}</p>
      {payload.map((p: any) => (
        <p key={p.dataKey} style={{ color: p.color }}>
          {p.name}: <span className="font-bold">{p.value}</span>
        </p>
      ))}
    </div>
  );
}

/* ─── Helper: parse score range ──────────────────────────── */
function marketTrendData(trends: string[]): { subject: string; score: number }[] {
  const keywords: Record<string, number> = { ai: 90, automation: 85, saas: 80, b2b: 75, mobile: 70, enterprise: 65, consumer: 60, blockchain: 50 };
  return trends.slice(0, 6).map((t, i) => {
    const lower = t.toLowerCase();
    const matched = Object.entries(keywords).find(([k]) => lower.includes(k));
    return { subject: t.slice(0, 20), score: matched ? matched[1] : 55 + i * 5 };
  });
}

function seededRand(seed: number, i: number): number {
  const x = Math.sin(seed + i * 9301 + 49297) * 233280;
  return Math.abs(x - Math.floor(x));
}

function growthData(seed: number): { month: string; demand: number; risk: number }[] {
  return Array.from({ length: 12 }, (_, i) => ({
    month: `M${i + 1}`,
    demand: Math.min(100, 40 + i * 5 + Math.round(seededRand(seed, i) * 8)),
    risk: Math.max(10, 55 - i * 3 + Math.round(seededRand(seed + 1, i) * 6)),
  }));
}

const RISK_SEVERITY: Record<string, "high" | "medium" | "low"> = {};
function getRiskSeverity(risk: string): "high" | "medium" | "low" {
  if (RISK_SEVERITY[risk]) return RISK_SEVERITY[risk];
  const lc = risk.toLowerCase();
  if (lc.includes("competi") || lc.includes("regulat") || lc.includes("depend")) return "high";
  if (lc.includes("enterprise") || lc.includes("scale") || lc.includes("integr")) return "medium";
  return "low";
}

const SEV_COLOR = { high: "text-red-400 bg-red-500/10 border-red-500/20", medium: "text-yellow-400 bg-yellow-500/10 border-yellow-500/20", low: "text-blue-400 bg-blue-500/10 border-blue-500/20" };

export function MarketFeasibilitySection() {
  const analysis = useAnalysisStore((s) => s.analysis);
  if (!analysis) return null;

  const { scoring, market_research, validation } = analysis;
  const demandScore = scoring.pillars.market_demand.score * 10;
  const radarData = marketTrendData(market_research.trends);
  const growthSeed = scoring.weighted_final_score + scoring.pillars.market_demand.score;
  const growth = growthData(growthSeed);

  return (
    <div className="space-y-4 max-w-5xl">
      <div>
        <h2 className="text-xl font-bold tracking-tight">Market Feasibility</h2>
        <p className="text-[13px] text-muted-foreground mt-1">
          Demand signal strength, growth trends, and risk landscape
        </p>
      </div>

      {/* Top row: gauge + radar */}
      <div className="grid md:grid-cols-2 gap-4">
        <SectionCard title="Market Demand Score">
          <DemandGauge score={demandScore} />
          <p className="text-center text-[12px] text-muted-foreground mt-4">
            {scoring.pillars.market_demand.explanation}
          </p>
          <div className="mt-4 grid grid-cols-3 gap-3">
            {(["uniqueness", "scalability", "stickiness"] as const).map((k) => (
              <div key={k} className="text-center">
                <div className="text-[18px] font-bold text-white/80">{scoring.pillars[k].score}<span className="text-[11px] text-white/30">/10</span></div>
                <div className="text-[10px] text-white/30 capitalize mt-0.5">{k.replace(/_/g, " ")}</div>
              </div>
            ))}
          </div>
        </SectionCard>

        <SectionCard title="Trend Signal Radar">
          <div className="h-[240px]">
            <ResponsiveContainer width="100%" height="100%">
              <RadarChart data={radarData} margin={{ top: 10, right: 20, bottom: 10, left: 20 }}>
                <PolarGrid stroke="rgba(255,255,255,0.07)" />
                <PolarAngleAxis dataKey="subject" tick={{ fill: "rgba(255,255,255,0.35)", fontSize: 10 }} />
                <Radar name="Signal" dataKey="score" stroke="rgba(99,102,241,0.8)" fill="rgba(99,102,241,0.18)" />
              </RadarChart>
            </ResponsiveContainer>
          </div>
        </SectionCard>
      </div>

      {/* Growth demand chart */}
      <SectionCard title="Projected Demand vs Risk Timeline (12 months)">
        <div className="h-[200px]">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={growth} margin={{ top: 5, right: 20, left: -10, bottom: 0 }}>
              <defs>
                <linearGradient id="demandGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="rgba(99,102,241,0.4)" />
                  <stop offset="95%" stopColor="rgba(99,102,241,0)" />
                </linearGradient>
                <linearGradient id="riskGrad" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="rgba(248,113,113,0.3)" />
                  <stop offset="95%" stopColor="rgba(248,113,113,0)" />
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.05)" />
              <XAxis dataKey="month" tick={{ fill: "rgba(255,255,255,0.3)", fontSize: 11 }} axisLine={false} tickLine={false} />
              <YAxis tick={{ fill: "rgba(255,255,255,0.3)", fontSize: 11 }} axisLine={false} tickLine={false} />
              <Tooltip content={<CustomTooltip />} />
              <Area type="monotone" dataKey="demand" name="Demand" stroke="rgba(99,102,241,0.8)" strokeWidth={2} fill="url(#demandGrad)" />
              <Area type="monotone" dataKey="risk" name="Risk" stroke="rgba(248,113,113,0.7)" strokeWidth={1.5} fill="url(#riskGrad)" strokeDasharray="4 2" />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </SectionCard>

      {/* Risk factors */}
      <SectionCard title="Risk Factors">
        <div className="grid sm:grid-cols-2 gap-3">
          {validation.risks.map((risk, i) => {
            const sev = getRiskSeverity(risk);
            return (
              <div key={i} className="flex items-start gap-3 p-3 rounded-xl border border-white/[0.06] bg-white/[0.02]">
                <div className="mt-0.5">
                  <span className={`text-[10px] font-semibold uppercase tracking-wider px-2 py-0.5 rounded-full border ${SEV_COLOR[sev]}`}>
                    {sev}
                  </span>
                </div>
                <p className="text-[12.5px] text-muted-foreground leading-snug">{risk}</p>
              </div>
            );
          })}
        </div>
      </SectionCard>

      {/* TAM/SAM/SOM */}
      <SectionCard title="Market Sizing">
        <div className="grid md:grid-cols-3 gap-4">
          {[
            { label: "TAM", sub: "Total Addressable Market", value: market_research.tam_sam_som.tam, color: "border-indigo-500/30 bg-indigo-500/5" },
            { label: "SAM", sub: "Serviceable Addressable", value: market_research.tam_sam_som.sam, color: "border-yellow-500/20 bg-yellow-500/5" },
            { label: "SOM", sub: "Serviceable Obtainable", value: market_research.tam_sam_som.som, color: "border-green-500/20 bg-green-500/5" },
          ].map(({ label, sub, value, color }) => (
            <div key={label} className={`rounded-xl border p-4 ${color}`}>
              <div className="text-[11px] font-semibold uppercase tracking-wider text-white/40 mb-1">{label}</div>
              <div className="text-[20px] font-black text-white/85 leading-tight mb-1">{value}</div>
              <div className="text-[10.5px] text-white/30">{sub}</div>
            </div>
          ))}
        </div>
        <p className="mt-4 text-[13px] text-muted-foreground leading-relaxed">{market_research.growth_outlook}</p>
      </SectionCard>
    </div>
  );
}

import { useAnalysisStore } from "@/store/useAnalysisStore";
import { SectionCard } from "../SectionCard";
import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip,
  ResponsiveContainer, PieChart, Pie, Cell, Legend,
} from "recharts";
import type { PricingTier } from "@/types/analysis";

/* ─── Deterministic hash for stable random-looking values ── */
function hashStr(s: string): number {
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (Math.imul(31, h) + s.charCodeAt(i)) | 0;
  return Math.abs(h);
}

/* ─── Parse price from hint string ─────────────────────── */
function parseLowestPrice(hint: string): number {
  const matches = hint.match(/\$(\d+)/g);
  if (!matches) return 0;
  return Math.min(...matches.map((m) => parseInt(m.replace("$", ""), 10)));
}

/* ─── Revenue projection ─────────────────────────────────── */
function generateMrrProjection(tiers: PricingTier[]): { month: string; conservative: number; realistic: number; optimistic: number }[] {
  const price = parseLowestPrice(tiers[0]?.price_hint ?? "$49") || 49;
  return Array.from({ length: 24 }, (_, i) => {
    const base = price * (i + 1) * 4;
    return {
      month: `M${i + 1}`,
      conservative: Math.round(base * 0.7),
      realistic:    Math.round(base * 1.1),
      optimistic:   Math.round(base * 1.55),
    };
  });
}

/* ─── Revenue stream pie ─────────────────────────────────── */
const STREAM_COLORS = ["#6366f1", "#8b5cf6", "#ec4899", "#f59e0b", "#10b981", "#3b82f6"];

/* ─── Custom tooltip ─────────────────────────────────────── */
function CustomTooltip({ active, payload, label }: { active?: boolean; payload?: any[]; label?: string }) {
  if (!active || !payload?.length) return null;
  return (
    <div className="bg-[#111] border border-white/[0.1] rounded-xl px-4 py-3 text-[12px] shadow-xl">
      <p className="text-white/40 mb-1.5">{label}</p>
      {payload.map((p: any) => (
        <p key={p.dataKey} className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full inline-block" style={{ background: p.color }} />
          <span className="text-white/50">{p.name}:</span>
          <span className="font-bold text-white/80">${p.value.toLocaleString()}</span>
        </p>
      ))}
    </div>
  );
}

const TIER_BADGE = ["Starter", "Pro", "Enterprise"];
const TIER_COLORS = [
  "border-white/[0.09] bg-white/[0.03]",
  "border-indigo-500/35 bg-indigo-500/8",
  "border-purple-500/30 bg-purple-500/6",
];

export function RevenueIntelligenceSection() {
  const analysis = useAnalysisStore((s) => s.analysis);
  if (!analysis) return null;

  const { monetization, competitor_analysis } = analysis;
  const projection = generateMrrProjection(monetization.pricing_tiers);

  const streamData = monetization.revenue_streams.map((s, i) => ({
    name: s,
    value: Math.round(100 / monetization.revenue_streams.length + (i % 3) * 8),
  }));

  const lastMonth = projection[projection.length - 1];

  return (
    <div className="space-y-4 max-w-5xl">
      <div>
        <h2 className="text-xl font-bold tracking-tight">Revenue Intelligence</h2>
        <p className="text-[13px] text-muted-foreground mt-1">
          Pricing strategy, revenue projections, and competitive pricing landscape
        </p>
      </div>

      {/* Key metrics */}
      <div className="grid grid-cols-3 gap-3">
        {[
          { label: "Y2 Conservative MRR", value: `$${Math.round(lastMonth.conservative * 0.6 / 1000)}K` },
          { label: "Y2 Realistic MRR",     value: `$${Math.round(lastMonth.realistic * 0.6 / 1000)}K` },
          { label: "Y2 Optimistic MRR",    value: `$${Math.round(lastMonth.optimistic * 0.6 / 1000)}K` },
        ].map(({ label, value }) => (
          <SectionCard key={label}>
            <div className="text-[11px] text-muted-foreground/60 mb-1">{label}</div>
            <div className="text-[26px] font-black text-white/85 leading-tight">{value}</div>
            <div className="text-[10.5px] text-muted-foreground/40">Monthly recurring</div>
          </SectionCard>
        ))}
      </div>

      {/* Pricing tiers */}
      <div className="grid md:grid-cols-3 gap-4">
        {monetization.pricing_tiers.map((tier, i) => (
          <div key={tier.name} className={`rounded-xl border p-5 relative overflow-hidden ${TIER_COLORS[i] ?? TIER_COLORS[2]}`}>
            {i === 1 && (
              <div className="absolute top-3 right-3 text-[9.5px] font-bold uppercase tracking-wider px-2 py-0.5 rounded-full bg-indigo-500/25 text-indigo-300 border border-indigo-500/30">
                Popular
              </div>
            )}
            <div className="text-[10px] font-semibold uppercase tracking-wider text-white/35 mb-2">{TIER_BADGE[i] ?? tier.name}</div>
            <div className="text-[22px] font-black text-white/90 mb-1">{tier.name}</div>
            <div className="text-[14px] font-semibold text-white/50 mb-3">{tier.price_hint}</div>
            <p className="text-[12px] text-muted-foreground leading-relaxed">{tier.reasoning}</p>
          </div>
        ))}
      </div>

      {/* MRR Projection chart */}
      <SectionCard title="MRR Projection — 24 Months">
